const today = new Date();
today.setHours(0,0,0,0);

return items
  .map(item => {
    const email = item.json["Employee Email"];
    const name = item.json["Name"];
    const startRaw = item.json["Start Date"];
    const endRaw = item.json["End Date"];
    const status = item.json["Status"] || "Inactive";

    // Validate required fields
    if (!email || !startRaw || !endRaw) {
      return null;
    }

    const startDate = new Date(startRaw);
    const endDate = new Date(endRaw);

    // Normalize time
    startDate.setHours(0,0,0,0);
    endDate.setHours(0,0,0,0);

    if (isNaN(startDate) || isNaN(endDate)) {
      return null;
    }

    const isWithinLeave = today >= startDate && today <= endDate;
    const isLeaveEnded = today > endDate;

    return {
      json: {
        email,
        name,
        startDate: startDate.toISOString().split("T")[0],
        endDate: endDate.toISOString().split("T")[0],
        returnDate: endDate.toISOString().split("T")[0],
        currentStatus: status,
        today: today.toISOString().split("T")[0],
        isWithinLeave,
        isLeaveEnded,
        needsActivation: isWithinLeave && status !== "Active",
        needsReset: isLeaveEnded && status === "Active"
      }
    };
  })
  .filter(item => item !== null);

